import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import { LineChart, ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface WeeklyTrend {
  day: string;
  rate: number;
}

interface CurrencyData {
  currencyPair: string;
  currentRate: number;
  change: number;
  changePercent: number;
  weeklyTrend: WeeklyTrend[];
}

export default function Widget() {
  const currencyData = response.data as CurrencyData;
  const { currencyPair, currentRate, change, changePercent, weeklyTrend } = currencyData;
  const isPositive = change >= 0;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              {currencyPair} Exchange Rate
            </Typography>
            <Typography variant="h4" sx={{ color: '#F8FAFC', fontWeight: 600, mb: 0.5 }}>
              {currentRate.toFixed(4)}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5}>
              {isPositive ? (
                <TrendingUp sx={{ fontSize: 16, color: '#10B981' }} />
              ) : (
                <TrendingDown sx={{ fontSize: 16, color: '#EF4444' }} />
              )}
              <Typography variant="body2" sx={{ color: isPositive ? '#10B981' : '#EF4444' }}>
                {isPositive ? '+' : ''}
                {change.toFixed(4)} ({changePercent.toFixed(2)}%)
              </Typography>
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: weeklyTrend.map((trend) => trend.rate),
                  color: '#3B82F6',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: weeklyTrend.map((trend) => trend.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'rate' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="rate"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
